```javascript
// Physics network simulation rebuilt from scratch.

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

const TAU = Math.PI * 2;
const GOLDEN_RATIO = 1.618;
const SQRT_HALF = 0.707;

// -----------------------------------------------------------------------------
// Tunable simulation settings
// -----------------------------------------------------------------------------

const settings = {
  attractionStrength: 4000,   // inverse-square attraction between every pair
  springStiffness: 0.004,     // default spring constant
  damping: 0.92,              // velocity damping per tick
  centerPull: 0.0003,         // weak pull toward world center
  maxParticles: 40,           // stream particle cap
  streamDecay: 0.04,          // particle damping basis
  cameraLerp: 0.06            // camera smoothing
};

// -----------------------------------------------------------------------------
// Nodes
// -----------------------------------------------------------------------------

const nodes = [
  { id: "hub",     label: "Hub",     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// -----------------------------------------------------------------------------
// Springs
// -----------------------------------------------------------------------------

const springs = [
  { a: "hub",   b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub",   b: "beta",    rest: 160, k: 0.005 },
  { a: "hub",   b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub",   b: "delta",   rest: 170, k: 0.004 },
  { a: "hub",   b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// -----------------------------------------------------------------------------
// Camera
// -----------------------------------------------------------------------------

const camera = { x: 400, y: 300, zoom: 1 };
const cameraTarget = { x: 400, y: 300, zoom: 1 };

// -----------------------------------------------------------------------------
// Stream particles
// -----------------------------------------------------------------------------

const streamParticles = [];

// -----------------------------------------------------------------------------
// Helpers
// -----------------------------------------------------------------------------

function getNodeById(id) {
  return nodes.find(node => node.id === id) || null;
}

// -----------------------------------------------------------------------------
// Main node physics
// -----------------------------------------------------------------------------

function updateNodePhysics() {
  // Pairwise attraction between all nodes.
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const a = nodes[i];
      const b = nodes[j];

      const dx = a.x - b.x;
      const dy = a.y - b.y;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;

      const force = settings.attractionStrength / (distance * distance);
      const fx = (dx / distance) * force;
      const fy = (dy / distance) * force;

      a.vx += fx;
      a.vy += fy;
      b.vx -= fx;
      b.vy -= fy;
    }
  }

  // Spring constraints.
  for (const spring of springs) {
    const a = getNodeById(spring.a);
    const b = getNodeById(spring.b);
    if (!a || !b) continue;

    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const distance = Math.sqrt(dx * dx + dy * dy) || 1;

    const extension = distance - spring.rest;
    const force = (spring.k || settings.springStiffness) * extension;

    const fx = (dx / distance) * force;
    const fy = (dy / distance) * force;

    a.vx += fx;
    a.vy += fy;
    b.vx -= fx;
    b.vy -= fy;
  }

  // Damping, weak centering force, and integration.
  for (const node of nodes) {
    node.vx += (400 - node.x) * settings.centerPull;
    node.vy += (300 - node.y) * settings.centerPull;

    node.vx *= settings.damping;
    node.vy *= settings.damping;

    node.x += node.vx;
    node.y += node.vy;
  }
}

// -----------------------------------------------------------------------------
// Stream particle spawning
// -----------------------------------------------------------------------------

function spawnStreamParticle() {
  if (streamParticles.length >= settings.maxParticles) return;

  const source = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * SQRT_HALF;

  streamParticles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * GOLDEN_RATIO) * SQRT_HALF
  });
}

// -----------------------------------------------------------------------------
// Stream particle update
// -----------------------------------------------------------------------------

function updateStreamParticles() {
  const drag = 1 - settings.streamDecay * 0.125;

  for (let i = streamParticles.length - 1; i >= 0; i--) {
    const p = streamParticles[i];

    p.age++;

    if (p.age > p.maxAge) {
      streamParticles.splice(i, 1);
      continue;
    }

    p.vx *= drag;
    p.vy *= drag;

    p.x += p.vx;
    p.y += p.vy;
  }
}

// -----------------------------------------------------------------------------
// Camera smoothing
// -----------------------------------------------------------------------------

function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * settings.cameraLerp;
  camera.y += (cameraTarget.y - camera.y) * settings.cameraLerp;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * settings.cameraLerp;
}

// -----------------------------------------------------------------------------
// Simulation loop
// -----------------------------------------------------------------------------

let tick = 0;

function stepSimulation() {
  updateNodePhysics();
  updateStreamParticles();
  updateCamera();

  if (tick % 3 === 0) {
    spawnStreamParticle();
  }

  tick++;
}

setInterval(stepSimulation, 10);
```

### What this simulation does
- Maintains a small graph of named nodes.
- Applies:
  - mutual inverse-square attraction between every pair of nodes
  - spring forces along selected connections
  - a weak pull toward the center `(400, 300)`
  - velocity damping
- Spawns decorative “stream” particles from random nodes every 3 ticks.
- Smoothly interpolates a camera toward a target.

### Notes
- The original code does not render anything; it only updates simulation state.
- The node radii and labels are preserved in effect, but the logic mainly uses position and velocity.
- `cameraTarget` starts equal to `camera`, so the camera remains still unless external code changes the target.

